---换位buff表演
---@class LBattleBuffActPosition
local LBattleBuffActPosition = classX("LBattleBuffActPosition",nil)
local _Step = {
    NONE = 0,
    RUNNING = 1,
    END = 2
}

function LBattleBuffActPosition:ctor(viewMgr)
    ---@type LBattleViewMgr
    self._viewMgr = viewMgr

    self._state = _Step.NONE
end


function LBattleBuffActPosition:Start(para)
    self._para = para
    self._endTime = para.endTime
    self:OnStart()
end

function LBattleBuffActPosition:OnRun(time)

    if self._state ~=  _Step.RUNNING then
        return
    end
    if time > self._endTime then
        self:OnEnd()
    end

end

function LBattleBuffActPosition:OnStart()
    self._state = _Step.RUNNING

    local side = self._para.side
    local effect = self._para.effect
    local duration = self._para.duration

    self._viewMgr:GetUnitMgr():SwapHero(side,effect,duration)
end

function LBattleBuffActPosition:OnEnd()
    self._state = _Step.END
end

function LBattleBuffActPosition:IsEnd()
    return self._state == _Step.END
end


return LBattleBuffActPosition